class Solution:
    def uniquePaths(self, m: int, n: int) -> int:
        from functools import lru_cache

        @lru_cache(None)
        def dp(i, j):
            # Base case: reached destination
            if i == m - 1 and j == n - 1:
                return 1
            # Out of bounds
            if i >= m or j >= n:
                return 0
            # Sum paths going right and down
            return dp(i + 1, j) + dp(i, j + 1)

        return dp(0, 0)

class Solution:
    def uniquePaths(self, m: int, n: int) -> int:
        # Initialize m x n grid
        dp = [[1] * n for _ in range(m)]  # first row and column already 1

        for i in range(1, m):
            for j in range(1, n):
                dp[i][j] = dp[i-1][j] + dp[i][j-1]

        return dp[m-1][n-1]

class Solution:
    def uniquePaths(self, m: int, n: int) -> int:
        # Only store one row at a time
        prev = [1] * n

        for i in range(1, m):
            curr = [1] * n  # left edge is always 1
            for j in range(1, n):
                curr[j] = curr[j-1] + prev[j]  # left + above
            prev = curr

        return prev[n-1]

class Solution:
    def uniquePaths(self, m: int, n: int) -> int:
        from math import comb
        # Total moves: (m-1) down + (n-1) right = m+n-2
        # Choose (m-1) positions for down moves
        return comb(m + n - 2, m - 1)

class Solution:
    def longestCommonSubsequence(self, text1: str, text2: str) -> int:
        from functools import lru_cache

        @lru_cache(None)
        def dp(i, j):
            # Base case: exhausted one string
            if i == len(text1) or j == len(text2):
                return 0
            # Match: include both characters
            if text1[i] == text2[j]:
                return 1 + dp(i + 1, j + 1)
            # No match: try skipping from either string
            return max(dp(i + 1, j), dp(i, j + 1))

        return dp(0, 0)

class Solution:
    def longestCommonSubsequence(self, text1: str, text2: str) -> int:
        m, n = len(text1), len(text2)
        # dp[i][j] = LCS of text1[:i] and text2[:j]
        dp = [[0] * (n + 1) for _ in range(m + 1)]

        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if text1[i - 1] == text2[j - 1]:
                    dp[i][j] = 1 + dp[i - 1][j - 1]  # match: take diagonal
                else:
                    dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])  # skip one

        return dp[m][n]

