        for i in range(1, m + 1):
            curr = [0] * (n + 1)
            for j in range(1, n + 1):
                if text1[i - 1] == text2[j - 1]:
                    curr[j] = 1 + prev[j - 1]
                else:
                    curr[j] = max(prev[j], curr[j - 1])
            prev = curr

        return prev[n]

class Solution:
    def maxProfit(self, prices: list[int]) -> int:
        # States: hold (own stock), sold (just sold, cooldown), rest (can buy)
        hold, sold, rest = float('-inf'), 0, 0

        for price in prices:
            prev_hold, prev_sold, prev_rest = hold, sold, rest

            hold = max(prev_hold, prev_rest - price)  # keep holding or buy
            sold = prev_hold + price                   # sell today
            rest = max(prev_rest, prev_sold)           # rest or exit cooldown

        return max(sold, rest)  # can't end holding a stock for max profit

class Solution:
    def change(self, amount: int, coins: list[int]) -> int:
        n = len(coins)
        # dp[i][a] = ways to make amount a using first i coins
        dp = [[0] * (amount + 1) for _ in range(n + 1)]

        # Base case: one way to make 0 (use no coins)
        for i in range(n + 1):
            dp[i][0] = 1

        for i in range(1, n + 1):
            for a in range(amount + 1):
                # Skip this coin
                dp[i][a] = dp[i - 1][a]
                # Use this coin (if possible)
                if a >= coins[i - 1]:
                    dp[i][a] += dp[i][a - coins[i - 1]]

        return dp[n][amount]

class Solution:
    def change(self, amount: int, coins: list[int]) -> int:
        # dp[a] = number of ways to make amount a
        dp = [0] * (amount + 1)
        dp[0] = 1  # one way to make 0: use no coins

        for coin in coins:
            for a in range(coin, amount + 1):
                dp[a] += dp[a - coin]  # use this coin

        return dp[amount]

class Solution:
    def findTargetSumWays(self, nums: list[int], target: int) -> int:
        from functools import lru_cache

        @lru_cache(None)
        def dp(i, total):
            if i == len(nums):
                return 1 if total == target else 0
            # try both + and -
            return dp(i + 1, total + nums[i]) + dp(i + 1, total - nums[i])

        return dp(0, 0)

class Solution:
    def findTargetSumWays(self, nums: list[int], target: int) -> int:
        total = sum(nums)
        # Check if target is reachable
        if abs(target) > total:
            return 0

        # Offset to handle negative sums: index = sum + total
        offset = total
        dp = [[0] * (2 * total + 1) for _ in range(len(nums) + 1)]
        dp[0][offset] = 1  # 0 sum with 0 nums

        for i in range(1, len(nums) + 1):
            for s in range(-total, total + 1):
                if dp[i - 1][s + offset] > 0:
                    # Add current number
                    dp[i][s + nums[i - 1] + offset] += dp[i - 1][s + offset]
                    # Subtract current number
                    dp[i][s - nums[i - 1] + offset] += dp[i - 1][s + offset]

        return dp[len(nums)][target + offset]

class Solution:
    def findTargetSumWays(self, nums: list[int], target: int) -> int:
        total = sum(nums)
        # If target is out of range or (total + target) is odd, no solution
        if abs(target) > total or (total + target) % 2 != 0:
            return 0

        subset_sum = (total + target) // 2

        # Count subsets with sum = subset_sum
        dp = [0] * (subset_sum + 1)
        dp[0] = 1  # one way to make 0: choose nothing

        for num in nums:
            # Traverse backwards to avoid using the same element multiple times
            for s in range(subset_sum, num - 1, -1):
                dp[s] += dp[s - num]

        return dp[subset_sum]

class Solution:
    def isInterleave(self, s1: str, s2: str, s3: str) -> bool:
        from functools import lru_cache

        if len(s1) + len(s2) != len(s3):
            return False

        @lru_cache(None)
        def dp(i, j):
            # Base case: consumed all strings
            if i + j == len(s3):
                return True

            # Try taking from s1
            if i < len(s1) and s1[i] == s3[i + j]:
                if dp(i + 1, j):
                    return True

            # Try taking from s2
            if j < len(s2) and s2[j] == s3[i + j]:
                if dp(i, j + 1):
                    return True

            return False

        return dp(0, 0)

class Solution:
    def isInterleave(self, s1: str, s2: str, s3: str) -> bool:
        m, n = len(s1), len(s2)
        if m + n != len(s3):
            return False

        # dp[i][j] = can form s3[:i+j] from s1[:i] and s2[:j]
        dp = [[False] * (n + 1) for _ in range(m + 1)]
        dp[0][0] = True

        # Fill first column (only using s1)
        for i in range(1, m + 1):
            dp[i][0] = dp[i - 1][0] and s1[i - 1] == s3[i - 1]

        # Fill first row (only using s2)
        for j in range(1, n + 1):
            dp[0][j] = dp[0][j - 1] and s2[j - 1] == s3[j - 1]

        # Fill the rest
        for i in range(1, m + 1):
            for j in range(1, n + 1):
                # Check if we can take from s1 or s2
                dp[i][j] = (
                    (dp[i - 1][j] and s1[i - 1] == s3[i + j - 1]) or
                    (dp[i][j - 1] and s2[j - 1] == s3[i + j - 1])
                )

        return dp[m][n]

class Solution:
    def isInterleave(self, s1: str, s2: str, s3: str) -> bool:
        m, n = len(s1), len(s2)
        if m + n != len(s3):
            return False

        # Use 1-D array for previous row
        prev = [False] * (n + 1)
        prev[0] = True

        # Fill first row (only using s2)
        for j in range(1, n + 1):
            prev[j] = prev[j - 1] and s2[j - 1] == s3[j - 1]

        # Process remaining rows
        for i in range(1, m + 1):
            curr = [False] * (n + 1)
            # First column (only using s1)
            curr[0] = prev[0] and s1[i - 1] == s3[i - 1]

            for j in range(1, n + 1):
                curr[j] = (
                    (prev[j] and s1[i - 1] == s3[i + j - 1]) or
                    (curr[j - 1] and s2[j - 1] == s3[i + j - 1])
                )
            prev = curr

        return prev[n]

class Solution:
    def minDistance(self, word1: str, word2: str) -> int:
        from functools import lru_cache

        @lru_cache(None)
        def dp(i, j):
            # Base cases
            if i == len(word1):
                return len(word2) - j  # insert remaining chars
            if j == len(word2):
                return len(word1) - i  # delete remaining chars

            # Characters match: no edit needed
            if word1[i] == word2[j]:
                return dp(i + 1, j + 1)

            # Try all three operations
            insert_op = dp(i, j + 1)      # insert word2[j]
            delete_op = dp(i + 1, j)      # delete word1[i]
            replace_op = dp(i + 1, j + 1)  # replace word1[i] with word2[j]

            return 1 + min(insert_op, delete_op, replace_op)

        return dp(0, 0)

class Solution:
    def minDistance(self, word1: str, word2: str) -> int:
        m, n = len(word1), len(word2)
        # dp[i][j] = min edits to convert word1[:i] to word2[:j]
        dp = [[0] * (n + 1) for _ in range(m + 1)]

        # Base cases
        for i in range(m + 1):
            dp[i][0] = i  # delete all i characters
        for j in range(n + 1):
            dp[0][j] = j  # insert all j characters

        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if word1[i - 1] == word2[j - 1]:
                    dp[i][j] = dp[i - 1][j - 1]  # no edit needed
                else:
                    dp[i][j] = 1 + min(
                        dp[i - 1][j],      # delete from word1
                        dp[i][j - 1],      # insert into word1
                        dp[i - 1][j - 1]   # replace
                    )

        return dp[m][n]

class Solution:
    def minDistance(self, word1: str, word2: str) -> int:
        m, n = len(word1), len(word2)
        prev = list(range(n + 1))  # base case for row 0

        for i in range(1, m + 1):
            curr = [i] + [0] * n  # base case for column 0
            for j in range(1, n + 1):
                if word1[i - 1] == word2[j - 1]:
                    curr[j] = prev[j - 1]
                else:
                    curr[j] = 1 + min(prev[j], curr[j - 1], prev[j - 1])
            prev = curr

        return prev[n]

class Solution:
    def updateMatrix(self, mat: List[List[int]]) -> List[List[int]]:
        m, n = len(mat), len(mat[0])
        outputMatrix = [[1e9 for _ in range(n)] for _ in range(m)]
        queue = deque((i, j, 0) for i in range(m) for j in range(n) if mat[i][j]==0)
        visited = set((i, j) for i in range(m) for j in range(n) if mat[i][j]==0)

        while queue:
            i, j, dist = queue.popleft()
            outputMatrix[i][j] = dist
            for di, dj in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
                newI, newJ = i+di, j+dj
                if 0<=newI<m and 0<=newJ<n and (newI, newJ) not in visited:
                    visited.add((newI,newJ))
                    queue.append((newI, newJ, dist+1))
        return outputMatrix

