class Solution:
    def updateMatrix(self, mat: List[List[int]]) -> List[List[int]]:
        m, n = len(mat), len(mat[0])
        for i in range(m):
            for j in range(n):
                if mat[i][j]!=0: mat[i][j] = min(mat[i-1][j] if 0<=i-1<m else 1e9, mat[i][j-1] if 0<=j-1<n else 1e9)+1
        for i in range(m)[::-1]:
            for j in range(n)[::-1]:
                if mat[i][j]!=0: mat[i][j] = min(mat[i][j], mat[i+1][j]+1 if 0<=i+1<m else 1e9, mat[i][j+1]+1 if 0<=j+1<n else 1e9)
        return mat

class Solution:
    def numberOfPaths(self, grid: List[List[int]], k: int) -> int:
        m, n, MOD = len(grid), len(grid[0]), 10**9+7
        dp = [[defaultdict(int) for _ in range(n+1)] for _ in range(m+1)]
        dp[m-1][n][0] = 1
        for i in range(m-1, -1, -1):
            for j in range(n-1, -1, -1):
                for key in dp[i][j+1]:
                    dp[i][j][(key+grid[i][j])%k] = dp[i][j+1][key]
                for key in dp[i+1][j]:
                    dp[i][j][(key+grid[i][j])%k] += dp[i+1][j][key]
                    dp[i][j][(key+grid[i][j])%k] %= MOD
        return dp[0][0][0]

