    def allPossibleFBT(self, n: int):
        if not n&1: return []

        dp = [[] for _ in range(n+1)]
        dp[1] = [TreeNode()]
        # tabulation
        for numNodes in range(1, n+1, 2):
            for i in range(1, numNodes, 2):
