class Solution:
    def generateTrees(self, n: int) -> List[Optional[TreeNode]]:

        @lru_cache(None)
        def dp(numsTuple):
            if len(numsTuple)==0: return [None]
            bstList = []
            for index, num in enumerate(numsTuple):
                for leftTree in dp(numsTuple[:index]):
                    for rightTree in dp(numsTuple[index+1:]):
                        bstList.append(TreeNode(num, leftTree, rightTree))
            return bstList

        return dp(tuple(range(1, n+1)))

class Solution:
    def longestIncreasingPath(self, matrix: list[list[int]]) -> int:
        if not matrix:
            return 0

        m, n = len(matrix), len(matrix[0])
        memo = {}  # (i, j) -> longest path starting at (i, j)

        def dfs(i, j):
            if (i, j) in memo:
                return memo[(i, j)]

            max_len = 1  # at least the cell itself
            for di, dj in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                ni, nj = i + di, j + dj
                if 0 <= ni < m and 0 <= nj < n and matrix[ni][nj] > matrix[i][j]:
                    max_len = max(max_len, 1 + dfs(ni, nj))

            memo[(i, j)] = max_len
            return max_len

        return max(dfs(i, j) for i in range(m) for j in range(n))

class Solution:
    def numDistinct(self, s: str, t: str) -> int:
        from functools import lru_cache

        @lru_cache(None)
        def dp(i, j):
            # Base case: matched all of t
            if j == len(t):
                return 1
            # Exhausted s but not t
            if i == len(s):
                return 0

            # Always can skip s[i]
            count = dp(i + 1, j)

            # If match, also count using this character
            if s[i] == t[j]:
                count += dp(i + 1, j + 1)

            return count

        return dp(0, 0)

class Solution:
    def numDistinct(self, s: str, t: str) -> int:
        m, n = len(s), len(t)
        # dp[i][j] = number of distinct subsequences of t[:j] in s[:i]
        dp = [[0] * (n + 1) for _ in range(m + 1)]

        # Base case: empty t is a subsequence of any s
        for i in range(m + 1):
            dp[i][0] = 1

        for i in range(1, m + 1):
            for j in range(1, n + 1):
                # Always can skip s[i-1]
                dp[i][j] = dp[i - 1][j]
                # If characters match, also add the count from matching
                if s[i - 1] == t[j - 1]:
                    dp[i][j] += dp[i - 1][j - 1]

        return dp[m][n]

class Solution:
    def numDistinct(self, s: str, t: str) -> int:
        n = len(t)
        prev = [1] + [0] * n  # prev[0] = 1 (empty t)

        for char_s in s:
            curr = [1] + [0] * n
            for j in range(1, n + 1):
                curr[j] = prev[j]  # skip char_s
                if char_s == t[j - 1]:
                    curr[j] += prev[j - 1]  # use match
            prev = curr

        return prev[n]

class Solution:
    def isMatch(self, s: str, p: str) -> bool:
        from functools import lru_cache

        @lru_cache(None)
        def dp(i, j):
            # Base case: both exhausted
            if j == len(p):
                return i == len(s)

            # Check if current characters match
            first_match = i < len(s) and (p[j] == s[i] or p[j] == '.')

            # Handle '*'
            if j + 1 < len(p) and p[j + 1] == '*':
                # Try: skip pattern (zero match) OR use match (one or more)
                return dp(i, j + 2) or (first_match and dp(i + 1, j))
            else:
                # No '*': must match current character
                return first_match and dp(i + 1, j + 1)

        return dp(0, 0)

class Solution:
    def isMatch(self, s: str, p: str) -> bool:
        m, n = len(s), len(p)
        # dp[i][j] = does s[:i] match p[:j]
        dp = [[False] * (n + 1) for _ in range(m + 1)]
        dp[0][0] = True  # empty matches empty

        # Handle patterns like a*, a*b*, etc. that can match empty string
        for j in range(2, n + 1):
            if p[j - 1] == '*':
                dp[0][j] = dp[0][j - 2]

        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if p[j - 1] == '*':
                    # '*' matches zero of the preceding element
                    dp[i][j] = dp[i][j - 2]
                    # '*' matches one or more: check if preceding char matches
                    if p[j - 2] == s[i - 1] or p[j - 2] == '.':
                        dp[i][j] = dp[i][j] or dp[i - 1][j]
                elif p[j - 1] == '.' or p[j - 1] == s[i - 1]:
                    dp[i][j] = dp[i - 1][j - 1]

        return dp[m][n]
